const businesses = $input.all().map(item => item.json);

// Helper to group businesses into size tiers based on reviews
function getSizeTier(reviewsCount) {
  if (reviewsCount <= 50) return 'small';
  if (reviewsCount <= 200) return 'medium';
  return 'large';
}

const competitorSets = [];

for (let i = 0; i < businesses.length; i++) {
  const subject = businesses[i];
  const subjectTier = getSizeTier(subject.reviewsCount);

  // Find competitors: must be the same category AND similar size tier
  let competitors = businesses.filter((b, idx) => {
    if (idx === i) return false; // Skip self
    const sameTier = getSizeTier(b.reviewsCount) === subjectTier;
    const sameCategory = b.categoryName === subject.categoryName;
    return sameTier && sameCategory;
  });

  // Fallback: If fewer than 2 competitors in the same tier, expand to just same category
  if (competitors.length < 2) {
    competitors = businesses.filter((b, idx) => {
      if (idx === i) return false;
      return b.categoryName === subject.categoryName;
    });
  }

  // Take top 5 competitors (sorted by review count for relevance)
  competitors = competitors
    .sort((a, b) => b.reviewsCount - a.reviewsCount)
    .slice(0, 5);

  // Only create a set if we have at least 2 competitors for a valid MCP comparison
  if (competitors.length >= 2) {
    competitorSets.push({
      subject: subject,
      competitors: competitors,
      setSize: competitors.length + 1
    });
  }
}

return competitorSets.map(set => ({ json: set }));

return items.map(item => {
  let raw = item.json.output;

  // Remove markdown code fences (```json ... ```)
  let cleaned = raw
    .replace(/```json\s*/i, '')  // remove opening ```json
    .replace(/```$/, '')         // remove closing ```
    .trim();

  // Convert string to JSON
  let parsed;
  try {
    parsed = JSON.parse(cleaned);
  } catch (err) {
    throw new Error("Invalid JSON format: " + err.message);
  }

  return {
    json: parsed
  };
});

const competitorSet = $input.item.json;
const allBusinesses = [competitorSet.subject, ...competitorSet.competitors];

function extractFacebookUrl(business) {
  // 1. Try Apify's enriched 'facebooks' array
  if (business.facebooks && Array.isArray(business.facebooks) && business.facebooks.length > 0) {
    return business.facebooks[0];
  }

  // 2. Aggressive Regex: Look for ANY facebook.com link anywhere in the business object
  const stringified = JSON.stringify(business);
  const fbMatch = stringified.match(/https?:\/\/(www\.)?facebook\.com\/[a-zA-Z0-9\.\-]+/);
  if (fbMatch) return fbMatch[0];

  // 3. Fallback: Generate a synthetic FB link from the website domain so AdSpy doesn't crash
  // e.g., https://pestcontrol.com -> https://facebook.com/pestcontrol
  if (business.website && typeof business.website === 'string' && !business.website.includes('google.com')) {
      try {
          const urlObj = new URL(business.website);
          let domainName = urlObj.hostname.replace('www.', '').split('.')[0];
          return `https://facebook.com/${domainName}`;
      } catch(e) {}
  }

  return null;
}

const payloadCompetitors = allBusinesses.map((b, index) => {
  return {
    name: b.inputProfileName || b.title || "Unknown Business",
    domain: extractFacebookUrl(b) || "no-fb-found",
    isSubject: index === 0
  };
}).filter(c => c.domain !== "no-fb-found");

const subject = payloadCompetitors.find(c => c.isSubject);
const competitors = payloadCompetitors.filter(c => !c.isSubject);

// If we STILL don't have enough data, output a visible error object instead of failing silently
if (!subject || competitors.length < 2) {
  return {
      json: {
          status: "error",
          reason: "Not enough valid Facebook URLs found",
          foundSubject: !!subject,
          competitorCount: competitors.length
      }
  };
}

return {
  json: {
    status: "success",
    competitors: [subject, ...competitors.slice(0, 5)]
  }
};

const response = $input.item.json;

// Handle failed analyses gracefully
if (!response || response.success === false) {
  return {
    json: {
      status: 'failed',
      subjectName: response?.subject?.name || 'Unknown',
      error: response?.error || 'Analysis failed or no ads found',
      timestamp: new Date().toISOString()
    }
  };
}

// Flatten the "Trojan Horse" insights for CRM / Cold Outreach
return {
  json: {
    status: 'success',
    analysis_id: response.analysis_id,
    subjectName: response.subject?.name || 'Unknown',
    subjectAdsCount: response.subject?.ad_count || 0,
    missingHooks: (response.gaps?.missing_hooks || []).join(', ') || 'N/A',
    underutilizedFormats: (response.gaps?.underutilized_formats || []).join(', ') || 'N/A',
    topRecommendationAction: response.recommendations?.[0]?.action || "",
    topRecommendationExample: response.recommendations?.[0]?.example || "",
    topRecommendationImplementation: response.recommendations?.[0]?.implementation || "",
    dominantMarketHook: response.market_insights?.dominant_hook_type || "N/A",
    competitorsAnalyzed: (response.competitors || []).map(c => c.name).join(', '),
    timestamp: new Date().toISOString()
  }
};

const allAnalyses = $input.all().map(item => item.json);

// Separate successes from failures
const successful = allAnalyses.filter(a => a.status === 'success');
const failed = allAnalyses.filter(a => a.status === 'failed');

return {
  json: {
    workflow_summary: {
      totalProcessed: allAnalyses.length,
      successfulAnalyses: successful.length,
      failedAnalyses: failed.length
    },
    readyForOutreach: successful,
    failedRecords: failed
  }
};
